import{_ as a,o as s,c as i,an as t}from"./chunks/framework.557DcZeb.js";const g=JSON.parse('{"title":"Getting started","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/index.md","filePath":"getting-started/index.md","lastUpdated":null}'),n={name:"getting-started/index.md"};function r(o,e,p,l,h,d){return s(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="getting-started" tabindex="-1">Getting started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting started {#getting-started}&quot;">​</a></h1><p>EpiAwarePackageTools (the kit) is the scaffolding toolkit for EpiAware Julia packages. It writes and keeps in sync the standard CI, documentation build, quality checks, and AD-gradient harness a package would otherwise copy by hand. This page is a quickstart; the home page is the full reference.</p><div class="tip custom-block"><p class="custom-block-title">This site is a live example of the generated output</p><p>This documentation is itself produced by the kit&#39;s scaffold. The navigation, the VitePress theme, the GitHub-stars widget in the navbar, the API reference, the release-notes page, and the badge table on the home page are all what <code>scaffold</code>/<code>scaffold_update</code> write for an adopting package. So this site doubles as a reference for what your package&#39;s docs will look like once it adopts the kit. See <a href="/epiawarepackagetools.epiaware.org/previews/PR262/getting-started/infrastructure#infrastructure">Infrastructure and template sync</a> for how the generated files are kept current.</p></div><h2 id="Adopting-the-kit" tabindex="-1">Adopting the kit <a class="header-anchor" href="#Adopting-the-kit" aria-label="Permalink to &quot;Adopting the kit {#Adopting-the-kit}&quot;">​</a></h2><p>Add EpiAwarePackageTools to a package&#39;s test environment, then scaffold once:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">using</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> EpiAwarePackageTools</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Adopt the standard tooling into an existing package.</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">scaffold</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">pkgdir</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(MyPackage))</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># A tooling / non-numerical package opts out of the AD infrastructure.</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">scaffold</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">pkgdir</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(MyTooling); ad </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p><code>scaffold</code> writes the managed standard files (CI callers, the docs build, formatter and coverage config, the QA and AD harness wiring) and a set of package-owned skeletons (the package&#39;s own unit tests, QA config values, AD scenarios, <code>LICENSE</code>, and the docs source pages you are reading now). Managed files are overwritten on every sync; package-owned files are written once and left for you to edit.</p><h2 id="Keeping-a-package-in-sync" tabindex="-1">Keeping a package in sync <a class="header-anchor" href="#Keeping-a-package-in-sync" aria-label="Permalink to &quot;Keeping a package in sync {#Keeping-a-package-in-sync}&quot;">​</a></h2><p><code>scaffold_update</code> re-applies only the managed files and reports what changed:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">scaffold_update</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">pkgdir</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(MyPackage))</span></span></code></pre></div><p>This is the entry point the scheduled template-sync workflow calls, so an improvement made once in the kit reaches every adopting package. See <a href="/epiawarepackagetools.epiaware.org/previews/PR262/getting-started/infrastructure#infrastructure">Infrastructure and template sync</a> for the full loop.</p><h2 id="Starting-a-fresh-package" tabindex="-1">Starting a fresh package <a class="header-anchor" href="#Starting-a-fresh-package" aria-label="Permalink to &quot;Starting a fresh package {#Starting-a-fresh-package}&quot;">​</a></h2><p><code>scaffold_generate</code> lays down a new package&#39;s <code>Project.toml</code> and source module, then scaffolds it:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">scaffold_generate</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;path/to/NewPkg&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;NewPkg&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h2 id="Learning-more" tabindex="-1">Learning more <a class="header-anchor" href="#Learning-more" aria-label="Permalink to &quot;Learning more {#Learning-more}&quot;">​</a></h2><ul><li><p>The home page documents every helper, the managed-versus-package-owned split, and the AD opt-in behaviour in full.</p></li><li><p>The <a href="/epiawarepackagetools.epiaware.org/previews/PR262/lib/public#public-api">Public API</a> lists the exported functions.</p></li><li><p>See <a href="/epiawarepackagetools.epiaware.org/previews/PR262/getting-started/customising#customising">Customising your docs</a> for how to make the seeded pages (this one included) your own.</p></li><li><p>Questions or problems? Open an issue on the <a href="https://github.com/EpiAware/EpiAwarePackageTools.jl" target="_blank" rel="noreferrer">GitHub repository</a>.</p></li></ul>`,16)])])}const k=a(n,[["render",r]]);export{g as __pageData,k as default};
